changeSet.sql:
-- Helper: hôm nay = GETDATE(). Tạo run NOW_SHOWING cho phim đang chiếu, -- SCHEDULED cho phim sắp chiếu, ENDED cho phim đã hết.
DECLARE @today DATE = CAST(GETDATE() AS DATE);
-- 5 phim đang NOW_SHOWING ở TẤT CẢ 5 chi nhánh -- (Avatar 3, Mai 2, John Wick 5, Doctor Strange 3, Conan 27) INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, -7, @today), DATEADD(DAY, 35, @today), N'FIRST_RUN', N'NOW_SHOWING', N'ACTIVE' FROM movies m CROSS JOIN theaters t WHERE m.title IN (N'Avatar 3: Lửa và Tro', N'Mai 2', N'John Wick 5', N'Marvel: Doctor Strange 3', N'Conan Movie 27');
-- 4 phim COMING_SOON cho TẤT CẢ 5 chi nhánh (Dune 3, MI9, Quỷ Cẩu 2, Lật Mặt 8) INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, 14, @today), DATEADD(DAY, 60, @today), N'FIRST_RUN', N'SCHEDULED', N'ACTIVE' FROM movies m CROSS JOIN theaters t WHERE m.title IN (N'Dune: Phần 3', N'Mission Impossible 9', N'Quỷ Cẩu 2: Trở Lại', N'Lật Mặt 8');
-- Phim ENDED (Em và Trịnh đã chiếu xong) tại HN/HCM INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, -90, @today), DATEADD(DAY, -30, @today), N'FIRST_RUN', N'ENDED', N'ACTIVE' FROM movies m, theaters t WHERE m.title = N'Em và Trịnh' AND t.code IN (N'CNX-HN', N'CNX-HCM');
-- REISSUE: Inception remaster đang chiếu ở HN + HCM (2 thành phố lớn) INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, -14, @today), DATEADD(DAY, 7, @today), N'REISSUE', N'NOW_SHOWING', N'ACTIVE' FROM movies m, theaters t WHERE m.title = N'Inception (Remaster)' AND t.code IN (N'CNX-HN', N'CNX-HCM');
-- REISSUE: Spirited Away open-ended (không endDate) chỉ ở HN — phim cổ điển arthouse INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, -30, @today), NULL, N'REISSUE', N'NOW_SHOWING', N'ACTIVE' FROM movies m, theaters t WHERE m.title = N'Spirited Away (Bản remaster 4K)' AND t.code = N'CNX-HN';
-- FESTIVAL: Liên Hoan Phim Pháp chiếu 7 ngày ở HN + HCM INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, 30, @today), DATEADD(DAY, 37, @today), N'FESTIVAL', N'SCHEDULED', N'ACTIVE' FROM movies m, theaters t WHERE m.title = N'Liên Hoan Phim Pháp 2026' AND t.code IN (N'CNX-HN', N'CNX-HCM');
-- Trẻ em: Doraemon + Tom & Jerry + Kungfu Panda 5 chiếu open-ended ở TẤT CẢ INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, -14, @today), NULL, N'FIRST_RUN', N'NOW_SHOWING', N'ACTIVE' FROM movies m CROSS JOIN theaters t WHERE m.title IN (N'Doraemon: Hành Tinh Khủng Long', N'Tom & Jerry: Phim Mới', N'Kungfu Panda 5');
-- Joker 2 reissue T18: chỉ chiếu HN art-house, ngắn 5 ngày INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, 7, @today), DATEADD(DAY, 12, @today), N'REISSUE', N'SCHEDULED', N'ACTIVE' FROM movies m, theaters t WHERE m.title = N'Joker 2: Folie à Deux (Re-issue)' AND t.code = N'CNX-HN';
-- Nhà Bà Nữ 2 đang chiếu các thành phố lớn HN + HCM + DN INSERT INTO movie_runs (movie_id, theater_id, start_date, end_date, run_type, status, storage_state) SELECT m.id, t.id, DATEADD(DAY, -10, @today), DATEADD(DAY, 25, @today), N'FIRST_RUN', N'NOW_SHOWING', N'ACTIVE' FROM movies m, theaters t WHERE m.title = N'Nhà Bà Nữ 2' AND t.code IN (N'CNX-HN', N'CNX-HCM', N'CNX-DN');
